1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office - quote (premium)", () => {
5	  // Fee-only baseline
6	  it("should charge 5 G (fee only) for an empty item list", () => {
7	    expect(quote([], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(5);
8	  });
9	
10	  // Single main item base premiums + fee
11	  it.todo("should quote a single sword at 105 G (100 base + 5 fee)");
12	  it.todo("should quote a single amulet at 65 G (60 base + 5 fee)");
13	  it.todo("should quote a single staff at 85 G (80 base + 5 fee)");
14	  it.todo("should quote a single potion at 45 G (40 base + 5 fee)");
15	
16	  // Multiple main items sum their base premiums
17	  it.todo("should sum base premiums for a sword and an amulet to 165 G (160 base + 5 fee)");
18	
19	  // Component base premiums
20	  it.todo("should quote a single rune at 30 G (25 base + 5 fee)");
21	  it.todo("should quote 2 runes at 55 G (50 base + 5 fee)");
22	
23	  // Building block of 3 alike components
24	  it.todo("should quote 3 runes as a block at 65 G (60 base + 5 fee)");
25	  it.todo("should quote 4 runes at 105 G (no block, 100 base + 5 fee)");
26	  it.todo("should quote 7 runes at 180 G (175 base + 5 fee)");
27	
28	  // Alike = same type only
29	  it.todo("should not form a block for 2 runes + 1 moonstone (75 base + 5 fee = 80 G)");
30	  it.todo("should form two separate blocks for 3 runes + 3 moonstones (120 base + 5 fee = 125 G)");
31	
32	  // Item-specific modifiers
33	  it.todo("should add 50% curse surcharge to the cursed item's base premium");
34	  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
35	  it.todo("should not add high-enchantment surcharge for enchantment 4");
36	  it.todo("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item");
37	
38	  // Modifier scope on multi-item policies
39	  it.todo("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before fee)");
40	
41	  // Policy-wide modifiers
42	  it.todo("should apply 20% loyalty discount for a customer with exactly 2 years");
43	  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
44	  it.todo("should apply 15% follow-up discount on quotes after the customer's first quote");
45	
46	  // Rounding up in MHPCO's favor
47	  it.todo("should round the final premium up (197.5 G becomes 198 G)");
48	
49	  // Integration examples
50	  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
51	  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");
52	
53	  // Error case
54	  it.todo("should reject a quote containing an item with an unknown type");
55	});
56	
57	describe("Claim Office - claim (payout)", () => {
58	  // Standard reimbursement minus deductible
59	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
60	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
61	
62	  // High-enchantment clause
63	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
64	
65	  // Dragon-material clause
66	  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");
67	
68	  // Conflict: 50% rule wins over dragon
69	  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");
70	
71	  // Threshold confirmation
72	  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");
73	
74	  // Deductible per damage event
75	  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");
76	
77	  // Cap behaviour
78	  it.todo("should cap total payout at twice the insurance sum");
79	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
80	
81	  // Rounding down in MHPCO's favor
82	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
83	
84	  // Error cases
85	  it.todo("should reject a claim whose damage entry references an item not in the policy");
86	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
87	  it.todo("should reject a claim with a negative damage amount");
88	});
